import Sortable from 'sortablejs';
import useForm from '../components/useForm';

const DOM_SELECTORS = {
    PRZELEWY24_ACCOUNT_TYPE_FORM: '.js-przelewy24-account-type-form',
    PRZELEWY24_ACCOUNT_TYPE_FORM_INPUT: '.js-przelewy24-account-type-input',
    PRZELEWY24_TABS_CONTENT: '.js-przelewy24-tabs-content',
    PRZELEWY24_TABS_CONTENT_FORM: '.js-przelewy24-tabs-content-form',
    PRZELEWY24_TABS_CONTENT_FORM_CONTENT: '.js-przelewy24-tabs-content-form-content',
    PRZELEWY24_CREDENTIALS_TEST_MODE_INPUT: '.js-przelewy24-credential-test-mode-input',
    PRZELEWY24_PAYMENT_COLLECTION: '.js-przelewy24-payment-collection',
    PRZELEWY24_PAYMENT_COLLECTION_ITEM: '.js-przelewy24-payment-collection-item',
    PRZELEWY24_PAYMENT_SWITCH: '.js-przelewy24-payment-switch',
    PRZELEWY24_MIGRATE_BUTTON: '.js-przelewy24-migrate-button',
};

const formController = () => {
    const {
        changeAccount,
        changeTestMode,
        formSubmit,
        migrate
    } = useForm();

    const toggleVisibility = (element, isVisible) => {
        if (isVisible) {
            element.classList.remove('d-none');
        } else {
            element.classList.add('d-none');
        }
    }

    const handlePositionChange = (group) => {
        const list = document.querySelector(`[data-group="${group}"][data-list-type="selected"]`);
        const input = document.getElementById(group);
        const items = list.querySelectorAll(DOM_SELECTORS.PRZELEWY24_PAYMENT_COLLECTION_ITEM);
        const positions = [];

        items.forEach((item, index) => {
            positions.push(item.dataset.id);
        });

        input.value = positions.join(',');
    };

    const initSortable = () => {
        const list = document.querySelectorAll(DOM_SELECTORS.PRZELEWY24_PAYMENT_COLLECTION);

        list.forEach((element) => {
            const group = element.dataset.group;

            Sortable.create(element, {
                group: group,
                animation: 200,
                onEnd: (event) => {
                    const { to } = event;

                    handlePositionChange(to.dataset.group);
                },
            });
        });
    };

    const handleTestModeChange = async (event) => {
        event.preventDefault();

        const input = event.currentTarget;
        const testMode = document.querySelector(`${DOM_SELECTORS.PRZELEWY24_CREDENTIALS_TEST_MODE_INPUT}:checked`).value;
        const idAccount = document.querySelector(`${DOM_SELECTORS.PRZELEWY24_ACCOUNT_TYPE_FORM_INPUT}:checked`).value;
        const url = input.dataset.url;
        const formContent = input.closest(DOM_SELECTORS.PRZELEWY24_TABS_CONTENT_FORM_CONTENT);

        try {
            const response = await changeTestMode(url, idAccount, testMode);

            if (response.content && formContent) {
                formContent.innerHTML = response.content;
            }
        } catch (errorResponse) {
            if (errorResponse.error) {
                console.log(errorResponse.error);
                window.showErrorMessage(errorResponse.error);
            } else {
                console.warn(errorResponse);
                window.showErrorMessage(errorResponse);
            }
        } finally {
            refresh();
        }
    };

    const handleAccountTypeChange = async (event) => {
        event.preventDefault();

        const input = event.currentTarget;
        const url = input.closest(DOM_SELECTORS.PRZELEWY24_ACCOUNT_TYPE_FORM).dataset.url;
        const idAccount = document.querySelector(`${DOM_SELECTORS.PRZELEWY24_ACCOUNT_TYPE_FORM_INPUT}:checked`).value;
        const tabsContent = document.querySelector(DOM_SELECTORS.PRZELEWY24_TABS_CONTENT);

        try {
            const response = await changeAccount(url, idAccount);

            window.showSuccessMessage('Account has been changed');

            if (response.content && tabsContent) {
                tabsContent.innerHTML = response.content;
            }
        } catch (errorResponse) {
            if (errorResponse.error) {
                console.log(errorResponse.error);
                window.showErrorMessage(errorResponse.error);
            } else {
                console.warn(errorResponse);
                window.showErrorMessage(errorResponse);
            }
        } finally {
            refresh();
        }
    };

    const handleFormSubmit = async (event) => {
        event.preventDefault();

        const form = event.currentTarget;
        const url = form.action;
        const formData = new URLSearchParams(new FormData(form)).toString();
        const fileInputs = form.querySelectorAll('input[type="file"]');
        const formContent = form.querySelector(DOM_SELECTORS.PRZELEWY24_TABS_CONTENT_FORM_CONTENT);
        const idAccount = document.querySelector(`${DOM_SELECTORS.PRZELEWY24_ACCOUNT_TYPE_FORM_INPUT}:checked`).value;

        const filesFormData = new FormData();
        let hasFiles = false;

        fileInputs.forEach(input => {
            if (input.files && input.files.length > 0) {
                hasFiles = true;
                filesFormData.append(input.name, input.files[0]);
            }
        });

        try {
            const response = await formSubmit(url, formData, idAccount, hasFiles ? filesFormData : null);

            window.showSuccessMessage('Changes have been saved');

            if (response.redirect) {
                window.location.href = response.redirect;
            } else if (response.content && formContent) {
                formContent.innerHTML = response.content;
            }
        } catch (errorResponse) {
            if (errorResponse.error) {
                console.log(errorResponse.error);
                window.showErrorMessage(errorResponse.error);
            } else {
                console.warn(errorResponse);
                window.showErrorMessage(errorResponse);
            }
        } finally {
            refresh();
        }
    };

    const togglePaymentListVisibility = (input) => {
        const targetElement = document.querySelector(input.dataset.target);
        const isVisible = input.checked && parseInt(input.value);

        toggleVisibility(targetElement, isVisible);
    }

    const handlePaymentSwitch = (event) => {
        togglePaymentListVisibility(event.currentTarget);
    }

    const initTogglePaymentListVisibility = () => {
        const paymentSwitches = document.querySelectorAll(`${DOM_SELECTORS.PRZELEWY24_PAYMENT_SWITCH}:checked`);

        paymentSwitches.forEach((input) => {
            togglePaymentListVisibility(input);
        });
    }

    const handleMigrate = async (event) => {
        event.preventDefault();
        const button = event.currentTarget;
        const url = button?.dataset.url;
        const message = button?.dataset.message;

        if (!url) {
            console.warn('URL not found');
            return;
        }

        if (!confirm(message || 'Are you sure?')) {
            return;
        }

        // The migrate function will redirect to the URL directly
        migrate(url);
        // No code will execute after this point as the page will be redirected
    }
    const attachEvents = () => {
        document.querySelectorAll(DOM_SELECTORS.PRZELEWY24_ACCOUNT_TYPE_FORM_INPUT).forEach((input) => {
            input.removeEventListener('change', handleAccountTypeChange);
            input.addEventListener('change', handleAccountTypeChange);
        });

        document.querySelectorAll(DOM_SELECTORS.PRZELEWY24_CREDENTIALS_TEST_MODE_INPUT).forEach((input) => {
            input.removeEventListener('change', handleTestModeChange);
            input.addEventListener('change', handleTestModeChange);
        });

        document.querySelectorAll(DOM_SELECTORS.PRZELEWY24_TABS_CONTENT_FORM).forEach((form) => {
            form.removeEventListener('submit', handleFormSubmit);
            form.addEventListener('submit', handleFormSubmit);
        });

        document.querySelectorAll(DOM_SELECTORS.PRZELEWY24_PAYMENT_SWITCH).forEach((input) => {
            input.removeEventListener('change', handlePaymentSwitch);
            input.addEventListener('change', handlePaymentSwitch);
        });

        document.querySelector(DOM_SELECTORS.PRZELEWY24_MIGRATE_BUTTON)?.removeEventListener('click', handleMigrate);
        document.querySelector(DOM_SELECTORS.PRZELEWY24_MIGRATE_BUTTON)?.addEventListener('click', handleMigrate);
        initSortable();
    };

    const init = () => {
        attachEvents();
        initTogglePaymentListVisibility();
    };

    const refresh = () => {
        attachEvents();
        initTogglePaymentListVisibility();
    }

    return {
        init,
    };
}

export default formController;
